    let timer;
    return function(...args) {
        //if a timer is already waiting to execute, remove it 
       clearTimeout(timer);

       timer = setTimeout(() => {
        // use fn.apply(this, args) instead of fn(...args), to behave correctly for objects methods as well
          fn.apply(this ,args); 
       }, t); 
    };
};
