/**
 * @param {Function} fn
 * @param {Array} args
 * @param {number} t
 * @return {Function}
 */
var cancellable = function(fn, args, t) {
    // Create variable timer to Schedule timer that will execute fn after t milliseconds
    const timer = setTimeout(function(){
        fn(...args);
    },t);

    //Return the cancel function
    //Calling this will prevent scheduled executuin 
    return function(){
        clearTimeout(timer);       // Cancels timer created by setTimeout
    }

};

